var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"나나하라 가문 연합 8봉인역 중심부.\\n관리불가판정 무인 침식지대.\\n구 나나하라 영지.","JPN":"七原家連合の第八封印域中心部。\\n管理不可判定を受けた侵食地帯。\\n旧七原家領地。","ENG":"The Center of the Nanahara Family Alliance’s 8th Seal Domain\\nUnmanageable, unmanned Corrupted area\\nOld Nanahara Territory","TWN":"七原家族第8封印域中心。\\n無法管理的無人侵蝕地區。\\n舊七原領地。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다시 돌아왔어.","JPN":"また戻って来たわ。","ENG":"I’m back.","TWN":"我又回來了。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"3년만에…….","JPN":"3年ぶりに……","ENG":"It’s been three years...","TWN":"睽違三年……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>살려 줘……</color>","JPN":"<color=#ff3636>助けて……</color>","ENG":"<color=#ff3636>Help me...</color>","TWN":"<color=#ff3636>救命……</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>몸이…… 끓고 있어. 독이……</color>","JPN":"<color=#ff3636>体が……熱い。毒が……</color>","ENG":"<color=#ff3636>My body... it’s boiling... The poison...</color>","TWN":"<color=#ff3636>身體……好像在沸騰。毒……</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>치나츠님은…… 어디에 계시지?</color>","JPN":"<color=#ff3636>千夏様は……いずこへ？</color>","ENG":"<color=#ff3636>Where is... Lady Nanahara?</color>","TWN":"<color=#ff3636>千夏堂主…… 在哪裡？</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>없어. 무능한 당주는…… 우릴 버리고 도망쳤지.</color>","JPN":"<color=#ff3636>いない。無能な当主は……我々を見捨てて逃げたんだ。</color>","ENG":"<color=#ff3636>She ran away... Our incompetent leader... deserted us...</color>","TWN":"<color=#ff3636>她不在，沒用的堂主……拋下我們逃走了。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제발……","JPN":"どうか……","ENG":"Please...","TWN":"拜託……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>나나하라 가문의 피를 바쳤다면, 살았을 거야.</color>","JPN":"<color=#ff3636>七原家門の血を捧げていれば、みんな助かったはずだ。</color>","ENG":"<color=#ff3636>We would have lived if she sacrificed herself.</color>","TWN":"<color=#ff3636>只要獻出七原家族的鮮血，就一定能活命的。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>하지만 겁쟁이 당주는 도망쳤지.</color>","JPN":"<color=#ff3636>なのに、臆病者の当主は逃げたんだ。</color>","ENG":"<color=#ff3636>But the coward ran away.</color>","TWN":"<color=#ff3636>膽小鬼堂主卻逃走了。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>결국 돌아올 거면서, 왜 그때 죽지 않은 건데?</color>","JPN":"<color=#ff3636>結局戻ってくるのなら、なぜあの時死ななかったんだ？</color>","ENG":"<color=#ff3636>If you were going to come back, why didn’t you die back then?</color>","TWN":"<color=#ff3636>既然都要回來，那當時怎麼不死一死？</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>우리의 기대를 배반했어.</color>","JPN":"<color=#ff3636>我々の期待を裏切った。</color>","ENG":"<color=#ff3636>You betrayed us.</color>","TWN":"<color=#ff3636>背叛我們的期待。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>거짓말로 연합원들을 속였어.</color>","JPN":"<color=#ff3636>嘘で連合員たちを騙した。</color>","ENG":"<color=#ff3636>You lied to us.</color>","TWN":"<color=#ff3636>說謊欺騙聯盟成員。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>겁쟁이.</color>","JPN":"<color=#ff3636>臆病者。</color>","ENG":"<color=#ff3636>Coward.</color>","TWN":"<color=#ff3636>膽小鬼。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>살인자.</color>","JPN":"<color=#ff3636>人殺し。</color>","ENG":"<color=#ff3636>Murderer.</color>","TWN":"<color=#ff3636>殺人兇手。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"아니야…… 난 거짓말을 한 게 아니야……","JPN":"違う……私は嘘をついたんじゃない……","ENG":"No... I didn’t lie to you...","TWN":"不是的……我沒有說謊……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>하지만 결과는 어땠지?</color>","JPN":"<color=#ff3636>それで結果はどうだった？</color>","ENG":"<color=#ff3636>But look what happened.</color>","TWN":"<color=#ff3636>結果怎麼樣呢？</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>넌 구차하게 살아 남았다. 그리고 모두가 죽었지.</color>","JPN":"<color=#ff3636>お前は卑しく生き延びた。そしてみんなは死んだ。</color>","ENG":"<color=#ff3636>You’re living your miserable life, while everyone is dead.</color>","TWN":"<color=#ff3636>你苟延殘喘地活下來，然後其他人都死光了。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>선대 당주는 살해당했을 뿐이지만, 너에겐 선택할 기회가 있었어.</color>","JPN":"<color=#ff3636>先代当主は殺害されたが、お前には選択する機会があった。</color>","ENG":"<color=#ff3636>Your predecessor was killed before she made her decision, but you had your chance.</color>","TWN":"<color=#ff3636>先祖堂主遭殺害沒得選，但你有選擇的機會的。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>하지만 넌 도망쳤을 뿐이지.</color>","JPN":"<color=#ff3636>お前は逃げただけなんだ。</color>","ENG":"<color=#ff3636>But you ran away.</color>","TWN":"<color=#ff3636>只是你選擇逃走。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>그들의 죽음을 등지고 도망쳤지.</color>","JPN":"<color=#ff3636>彼らの死に背を向けて逃げただけだ。</color>","ENG":"<color=#ff3636>Leaving your people behind to die.</color>","TWN":"<color=#ff3636>任他們去死，你自己逃走。</color>"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……그만!","JPN":"……もうやめて！","ENG":"... Stop!","TWN":"……住口！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"헉…… 허억……","JPN":"はぁ……はぁ……","ENG":"*Pant*","TWN":"呼……呼呼……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"서둘러, 의식을 준비해야…… 해.","JPN":"急いで、儀式の準備を……しなければ。","ENG":"I have to get ready... for the ritual...","TWN":"動作快，要準備……儀式。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……봉인 전승?","JPN":"……封印伝承？","ENG":"... The legend regarding the seal?","TWN":"……傳承封印？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"네. 무녀의 피와 혼이 봉인을 다스린다는 전승입니다.","JPN":"はい。巫女の血と魂が封印を強めるという伝承です。","ENG":"Yes. According to the legend, the blood and soul of the priestess can contain the seal.","TWN":"是的。巫女的血和靈魂是控制封印的傳承。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"최초에 오로치의 봉인은 불안정했습니다. 그것을 나나하라 가문의 초대 당주가 자신의 혼을 바쳐 완성시켰죠.","JPN":"当初のオロチの封印は不安定でした。\\nそれを七原家の初代当主が自身の魂を捧げて完成させたのです。","ENG":"In the beginning, the seal of Orochi was very unstable. The first Nanahara family leader sacrificed her soul to stabilize it.","TWN":"原本大蛇的封印是不穩定的。是七原家族初代堂主獻出自己的靈魂才將其完成。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그 희생으로 인해, 후손들의 피에도 오로치의 봉인을 수복하는 힘이 깃들어 있습니다.","JPN":"その犠牲により、子孫の血にもオロチの封印を修復する力が宿っています。","ENG":"Since then, her descendants gained the power to repair the seal using their blood.","TWN":"初代堂主的犧牲，導致其後代子孫的血液中，也有可以封印大蛇的能力。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그럼 치나츠가 말한 계획은 결국…….","JPN":"つまり千夏が話していた計画は……","ENG":"So Chinatsu’s plan is...","TWN":"所以千夏說的辦法就是……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"자기 자신을 희생해서 봉인을 수복하려는 거란 말이야?","JPN":"自分自身を犠牲にして封印を修復するってこと？","ENG":"To sacrifice herself to repair the seal?","TWN":"要犧牲自己恢復封印嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……오로치는 세상에 마지막이 오기 전까지 봉인되어 있어야 합니다.","JPN":"……オロチは世界が終わるまで封印されていなければなりません。","ENG":"Orochi must be sealed until the end of the world.","TWN":"……世界末日來臨前，大蛇必須被封印起來。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"어떤 이유에서든 그 봉인이 파괴될 징조를 보인다면…….","JPN":"どんな理由であれ、その封印が解ける兆しを見せた時は……","ENG":"If the seal is broken for some reason...","TWN":"無論原因是什麼，只要發現封印有遭破壞的跡象……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"호위 무사가 나나하라 가문의 보검으로 당주를 제단에 바쳐야 합니다.","JPN":"護衛が七原家の宝剣で当主を祭壇に捧げなければなりません。","ENG":"The bodyguard has to sacrifice her Lady using the family’s treasured sword.","TWN":"護衛武士就必須用七原家族的寶劍，將堂主獻在祭壇上。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇게 함으로써, 오로치의 해방이 유예되는 것이죠.","JPN":"そうすることでオロチの封印が強まるのです。","ENG":"That’s the only way to contain Orochi within the seal.","TWN":"如此才能延後大蛇被釋放的時間。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그럼 치후유가 당주가 되려고 했던 것도…… 치나츠 대신 희생하기 위해서구나.","JPN":"じゃあ千冬が当主になろうとしていたのは……\\n千夏の代わりに犠牲になるため、だったんだね。","ENG":"Chifuyu, you wanted to be the family leader because you wanted to... sacrifice yourself instead of her.","TWN":"所以你千冬想成爲堂主……也是因為想代替千夏犧牲嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇습니다. 초대 당주의 피를 이어받은 것은 저 또한 마찬가지니까요.","JPN":"そのとおりです。私も初代当主の血を継いだ者ですから。","ENG":"Yes. We share the same blood.","TWN":"是，我身上也留著初代堂主的血液。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 의식을 치렀다면…… 당주의 자리도 다시 자연스레 언니에게 돌아갔겠죠.","JPN":"私が儀式を行えば……当主の座は再び姉上に戻ったことでしょう。","ENG":"If I performed the ritual... my sister would have gotten her position back.","TWN":"等我舉行儀式後……堂主的位子自然會再回到姊姊那裡。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공이 방해하지만 않았다면 말입니다.","JPN":"奈由香殿の邪魔さえなければの話ですが。","ENG":"But then you interfered with my plan, Mr. Nayuka.","TWN":"前提是你沒妨礙我的話。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"다른 방법은…… 정말 없다고 생각해?","JPN":"本当に……他の方法はないのかな？","ENG":"Are you sure this is the only way?","TWN":"你認為……真的沒有其他辦法嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그런 방법이 있을지도 모른다는 희망 때문에 3년 전에도 많은 연합원들이 희생됐습니다.","JPN":"他の方法があるかもしれないという希望を持ったせいで、\\n3年前に大勢の連合員が犠牲になりました。","ENG":"Three years ago, many people lost their lives because they thought there might be another way.","TWN":"我們曾經奢望有其他辦法，結果卻是在3年前造成許多聯盟成員的犧牲。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"언니가 미래에서 엿본 파국을 막기 위해 연합원들을 모았지만…….","JPN":"姉上が垣間見た未来の悲劇を阻止するために連合員を集めましたが……","ENG":"My sister summoned all the Alliance members to stop the coming disaster...","TWN":"雖然姊姊召集聯盟成員，想阻止她在未來看到的悲劇……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"결국 실패하고 말았죠.","JPN":"結局、失敗に終わりました。","ENG":"But we failed.","TWN":"結果還是失敗收場。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"언니는 그날 이후로 매일 스스로를 책망했습니다.","JPN":"姉上はその日以来、毎日自分のことを責めていました。","ENG":"Since that day, my sister has blamed herself for what happened.","TWN":"姊姊從那天開始每天責備自己。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"속앓이와 오해와 모함뿐인 시간이었습니다.","JPN":"心痛と誤解と謀略だけの時間でした。","ENG":"It’s been a time of defamation and agony.","TWN":"那段時間只有痛苦、誤會和誣陷。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그러니 이제 누군가는…… 이 곯아가는 상처를 도려내야 합니다.","JPN":"だから誰かが……この膿んでいく傷を取り除かねばなりません。","ENG":"Now... someone has to end this.","TWN":"所以現在必須有人……挖掉這個腐爛的傷口。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};